"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[47701],{98570:(n,e,i)=>{i.r(e),i.d(e,{data:()=>l});const l={key:"v-63cd5dba",path:"/python/",title:"Python简单爬虫的实现",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1653545105e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"python/README.md"}},68617:(n,e,i)=>{i.r(e),i.d(e,{default:()=>d});const l=(0,i(57293).uE)('<h1 id="python简单爬虫的实现" tabindex="-1"><a class="header-anchor" href="#python简单爬虫的实现" aria-hidden="true">#</a> Python简单爬虫的实现</h1><p>今天在慕课网上学习了如何制作一个简单的Python爬虫，主要的功能就是从百度百科中获取关于Python的1000条数据。</p><p>1.要制作一个简单的爬虫程序需要有5个模块</p><p>（1）入口程序：在这个文件中定义了爬虫类，和调用爬虫的方法，爬虫类有2个函数，<strong>第一个是__init__函数</strong>，在爬虫类实例化的时候把url管理器,网页下载器,网页解析器和网页输出器赋值给爬虫类；<strong>第二个是craw函数</strong>，该函数用于爬取数据，调用该方法需要传入一个url，爬虫程序首先抓取此url对应的网页内容,其他的url都是解析网页时获取的。</p><p>（2）url管理器：在这个文件中定义了一个url管理类,主要有5个函数,<strong>第一个是__init__函数</strong>,在url管理类实例化时赋予它2个set(),分别用来存储待爬取的网页url和已爬取的网页url；<strong>第二，三个是add_new_url，add_new_urls函数</strong>，分别是向url管理器中添加单个url和批量添加url,在添加之前必须先判断url是否为空和是否已经在已爬取url或待爬取url中，有些网页可能存在2个网页相互引用，如此可以防止爬虫陷入循环；<strong>第四个是has_new_url函数</strong>，用于判断是否还有待爬取的url;<strong>第5个是get_new_url函数</strong>,用于获取新的待爬取的url;</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>#coding:utf-8\n&#39;&#39;&#39;\nCreated on 2017-6-27\n&#39;&#39;&#39;\n\nclass UrlManager(object):\n  def __init__(self):\n    self.new_urls=set()\n    self.old_urls=set()\n  \n  #向管理器中添加一个新的url\n  def add_new_url(self,url):\n    if(url is None):\n      return\n    if url not in self.new_urls and url not in self.old_urls:  #url既不在已爬取url列表,也不在待爬取url列表\n      self.new_urls.add(url)\n  #向管理器中添加批量的url\n  def add_new_urls(self,urls):\n    print(urls)\n    if urls is None or len(urls)==0:\n      return\n    for url in urls:\n      self.add_new_url(url)\n  #判断管理器中是否有新的,待爬取的url\n  def has_new_url(self):\n    return len(self.new_urls)!=0\n\n\n  #从管理器中获取一个新的待爬取得url\n  def get_new_url(self):\n    new_url=self.new_urls.pop()\n    self.old_urls.add(new_url)\n    return new_url\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（3）网页下载器：在这个文件中定义了网页下载类，类只有一个download函数，用于下载url对应的网页内容，<strong>在python2中下载网页内容需要用到urllib2模块，而在python3中使用from urllib import request，相关知识自行百度.</strong></p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code># coding:utf-8\n&#39;&#39;&#39;\n网页下载器\nCreated on 2017-6-27\n&#39;&#39;&#39;\n\n\nfrom urllib import request\n\nclass HtmlDownloader(object): \n  def download(self,url):\n    if url is None:\n      return None\n    response=request.urlopen(url)\n    if response.getcode()!=200:\n      return None\n    return response.read()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（4）网页解析器：顾名思义，就是用来分析网页内容的，不同的网页解析规则并不相同，本程序中的网页解析方法并不通用，如果需要解析其他网页内容，请自行修改函数。</p><p>文件定义了一个网页解析类，有3个方法,<strong>第一个是_get_new_urls函数</strong>，用于从下载的网页内容中获取符合筛选条件的url,<strong>第二个是_get_new_data函数</strong>，用于从获取自己需要的数据，<strong>第三个是parse函数</strong>，返回解析出来的数据。</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code># coding:utf-8\n&#39;&#39;&#39;\n网页解析器\nCreated on 2017-6-27\n&#39;&#39;&#39;\n\nfrom bs4 import BeautifulSoup\nimport re\nfrom urllib.parse import urljoin\nclass HtmlParser(object):\n   \n  def _get_new_urls(self, page_url, soup):\n    new_urls=set()\n    links=soup.find_all(&#39;a&#39;,href=re.compile(r&quot;/item/\\.*&quot;))\n    for link in links:\n      new_url=link[&quot;href&quot;]\n      new_full_url=urljoin(page_url,new_url)\n      new_urls.add(new_full_url)\n    return new_urls\n  \n  \n  def _get_new_data(self, page_url, soup):\n    res_data={}\n    res_data[&#39;url&#39;]=page_url\n    title_node=soup.find(&#39;dd&#39;,class_=&quot;lemmaWgt-lemmaTitle-title&quot;).find(&quot;h1&quot;)\n    res_data[&#39;title&#39;]=title_node.get_text()\n    \n    summary_node=soup.find(&quot;div&quot;,class_=&quot;lemma-summary&quot;)\n    res_data[&#39;summary&#39;]=summary_node.get_text()\n    return res_data\n  \n  \n  def parse(self,page_url,html_cont):\n    if page_url is None or html_cont is None:\n      return\n    soup=BeautifulSoup(html_cont,&#39;html.parser&#39;)\n    new_urls=self._get_new_urls(page_url,soup)\n    new_data=self._get_new_data(page_url,soup)\n    return new_urls,new_data\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（5）网页输出器：我们从目标网站获取到数据之后不可能什么都不做，所以需要使用网页输出器来把数据组织成我们需要的。文件定义了网页输出类，有3个方法，<strong>第一个是__init__函数</strong>，用于给类初始化一个datas，用于存储数据;<strong>第二个是collect_data函数</strong>，需要传入data,把data添加到datas中；<strong>第三个是output_html函数</strong>，当所有网页解析完，或者达到要求时，所有网页的数据都存储在datas中,在output_html函数中循环遍历datas，把数据组织成自己想要的格式。</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code># coding:utf-8\n&#39;&#39;&#39;\n网页输出器\nCreated on 2017-6-27\n&#39;&#39;&#39;\nimport io\nimport sys\n\n\nclass HtmlOutputer(object):\n    def __init__(self):\n        self.datas=[]\n        \n    \n    def collect_data(self,data):\n        if data is None:\n            return\n        self.datas.append(data)\n\n\n    \n    def output_html(self):\n        fout=open(&#39;output.html&#39;,&#39;w&#39;,encoding=&#39;utf-8&#39;)\n        fout.write(&#39;&lt;HTML&gt;&#39;)\n        fout.write(&#39;&lt;head&gt;&#39;)\n        fout.write(&#39;&lt;meta charset=&quot;utf-8&quot;&gt;&#39;)\n        fout.write(&#39;&lt;/head&gt;&#39;)\n        fout.write(&#39;&lt;body&gt;&#39;)\n        fout.write(&#39;&lt;table&gt;&#39;)\n        for data in self.datas:\n            fout.write(&#39;&lt;tr&gt;&#39;)\n            fout.write(&#39;&lt;td&gt;%s&lt;/td&gt;&#39; % data[&#39;url&#39;])\n            fout.write(&#39;&lt;td&gt;%s&lt;/td&gt;&#39; % (data[&#39;title&#39;]))\n            fout.write(&#39;&lt;td&gt;%s&lt;/td&gt;&#39; % data[&#39;summary&#39;])\n        fout.write(&#39;&lt;/table&gt;&#39;)\n        fout.write(&#39;&lt;/body&gt;&#39;)\n        fout.write(&#39;&lt;/HTML&gt;&#39;)\n        fout.close()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>2.在教程中要把中文写入到文件需要把数据进行（.encode(&quot;utf-8&quot;)）转换，但是我转换之后输出了二进制数据，再使用(decode(&quot;utf-8&quot;))也一直报错。百度了好久，之后在打开文件时指定编码格式（ fout=open(&#39;output.html&#39;,&#39;w&#39;,<strong>encoding=&#39;utf-8&#39;</strong>)）问题就解决了。</p>',14),s={},d=(0,i(63243).Z)(s,[["render",function(n,e){return l}]])},63243:(n,e)=>{e.Z=(n,e)=>{const i=n.__vccOpts||n;for(const[n,l]of e)i[n]=l;return i}}}]);